import React, { useState, useEffect } from 'react';

export default function App() {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const formatTime = (date) => {
    return date.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: true,
    });
  };

  const formatDate = (date) => {
    return date.toLocaleDateString('en-US', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  };

  return (
    <div className="min-h-screen bg-neutral-950 text-neutral-100 flex flex-col items-center justify-center p-4">
      <div className="w-full max-w-md bg-neutral-900 border border-neutral-800 rounded-3xl p-8 shadow-2xl shadow-black/50 backdrop-blur-md bg-opacity-50">
        <div className="text-center">
          <div className="text-neutral-400 text-sm font-medium uppercase tracking-widest mb-2">
            Local Time
          </div>
          <div className="text-6xl font-light font-mono tracking-tight text-white mb-2">
            {formatTime(time)}
          </div>
          <div className="text-neutral-500 font-medium">
            {formatDate(time)}
          </div>
        </div>

        <div className="mt-8 pt-8 border-t border-neutral-800 grid grid-cols-2 gap-4">
          <div className="bg-neutral-950 rounded-2xl p-4 border border-neutral-800">
            <div className="text-neutral-500 text-xs uppercase mb-1">Timezone</div>
            <div className="font-semibold text-blue-500">{Intl.DateTimeFormat().resolvedOptions().timeZone}</div>
          </div>
          <div className="bg-neutral-950 rounded-2xl p-4 border border-neutral-800">
            <div className="text-neutral-500 text-xs uppercase mb-1">Status</div>
            <div className="flex items-center gap-2">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
              </span>
              <span className="text-green-500 text-sm font-medium">Syncing</span>
            </div>
          </div>
        </div>
      </div>

      <footer className="text-center p-4 text-neutral-400 text-xs opacity-80 flex justify-center items-center gap-1.5 mt-auto">
        <span>Built with</span> 
        <img src="https://forge-app.vercel.app/logo.png" alt="Forge" className="w-3.5 h-3.5 rounded-sm object-cover" /> 
        <a href="https://forge-app.vercel.app" className="text-blue-500 font-semibold tracking-wide no-underline">FORGE</a>
      </footer>
    </div>
  );
}
